sealed class SocialLoginResult {
    data class Success(
        val provider: Provider,
        val accessToken: String,
        val idToken: String? = null,
        val tokenType: String? = null,
        val expiresInSeconds: Long? = null,
        val raw: JSONObject? = null
    ) : SocialLoginResult()

    data class Cancelled(val provider: Provider) : SocialLoginResult()
    data class Error(val provider: Provider, val message: String, val cause: Throwable? = null) : SocialLoginResult()
}

enum class Provider { GOOGLE, FACEBOOK }

data class OAuthRequest(
    val provider: Provider,
    val redirectUri: String = SocialLoginConfig.DEFAULT_REDIRECT_URI,
    val scopes: List<String>,
    val state: String = OAuthState.newState(),
    val nonce: String? = if (provider == Provider.GOOGLE) OAuthState.newNonce() else null
)

object OAuthState {
    private val rng = SecureRandom()

    fun newState(): String = randomUrlSafe(32)
    fun newNonce(): String = randomUrlSafe(32)

    private fun randomUrlSafe(bytes: Int): String {
        val b = ByteArray(bytes)
        rng.nextBytes(b)
        return Base64.encodeToString(b, Base64.URL_SAFE or Base64.NO_WRAP or Base64.NO_PADDING)
    }
}

class SocialLoginModule(
    private val activity: FragmentActivity,
    private val redirectUri: String = SocialLoginConfig.DEFAULT_REDIRECT_URI,
    private val httpClient: OkHttpClient = OkHttpClient.Builder()
        .callTimeout(30, TimeUnit.SECONDS)
        .connectTimeout(15, TimeUnit.SECONDS)
        .readTimeout(30, TimeUnit.SECONDS)
        .build()
) : DefaultLifecycleObserver {

    private val launcher: ActivityResultLauncher<Intent>
    private var pending: Pending? = null

    private data class Pending(
        val request: OAuthRequest,
        val callback: (SocialLoginResult) -> Unit
    )

    init {
        launcher = activity.registerForActivityResult(ActivityResultContracts.StartActivityForResult()) { result ->
            handleActivityResult(result)
        }
        activity.lifecycle.addObserver(this)
    }

    override fun onDestroy(owner: LifecycleOwner) {
        pending = null
    }

    @MainThread
    fun loginWithGoogle(
        scopes: List<String> = listOf("openid", "email", "profile"),
        callback: (SocialLoginResult) -> Unit
    ) {
        val req = OAuthRequest(
            provider = Provider.GOOGLE,
            redirectUri = redirectUri,
            scopes = scopes
        )
        startAuth(req, callback)
    }

    @MainThread
    fun loginWithFacebook(
        scopes: List<String> = listOf("public_profile", "email"),
        callback: (SocialLoginResult) -> Unit
    ) {
        val req = OAuthRequest(
            provider = Provider.FACEBOOK,
            redirectUri = redirectUri,
            scopes = scopes
        )
        startAuth(req, callback)
    }

    @MainThread
    private fun startAuth(request: OAuthRequest, callback: (SocialLoginResult) -> Unit) {
        if (pending != null) {
            callback(SocialLoginResult.Error(request.provider, "Another login is already in progress"))
            return
        }
        pending = Pending(request, callback)

        val authUri = when (request.provider) {
            Provider.GOOGLE -> buildGoogleAuthUri(request)
            Provider.FACEBOOK -> buildFacebookAuthUri(request)
        }

        val intent = Intent(activity, OAuthBrowserActivity::class.java).apply {
            putExtra(OAuthBrowserActivity.EXTRA_AUTH_URI, authUri.toString())
            putExtra(OAuthBrowserActivity.EXTRA_REDIRECT_URI, request.redirectUri)
        }
        launcher.launch(intent)
    }

    private fun handleActivityResult(result: ActivityResult) {
        val p = pending ?: return
        val data = result.data
        if (result.resultCode != Activity.RESULT_OK || data == null) {
            pending = null
            p.callback(SocialLoginResult.Cancelled(p.request.provider))
            return
        }

        val redirect = data.getStringExtra(OAuthBrowserActivity.EXTRA_RESULT_REDIRECT_URI)
        if (redirect.isNullOrBlank()) {
            pending = null
            p.callback(SocialLoginResult.Error(p.request.provider, "Missing redirect URI result"))
            return
        }

        val uri = Uri.parse(redirect)
        val error = uri.getQueryParameter("error")
        val errorDesc = uri.getQueryParameter("error_description") ?: uri.getQueryParameter("error_message")
        if (!error.isNullOrBlank()) {
            pending = null
            p.callback(SocialLoginResult.Error(p.request.provider, "$error${if (!errorDesc.isNullOrBlank()) ": $errorDesc" else ""}"))
            return
        }

        val state = uri.getQueryParameter("state")
        if (state.isNullOrBlank() || state != p.request.state) {
            pending = null
            p.callback(SocialLoginResult.Error(p.request.provider, "State mismatch"))
            return
        }

        when (p.request.provider) {
            Provider.GOOGLE -> {
                val code = uri.getQueryParameter("code")
                if (code.isNullOrBlank()) {
                    pending = null
                    p.callback(SocialLoginResult.Error(Provider.GOOGLE, "Missing authorization code"))
                    return
                }
                exchangeGoogleCode(code, p)
            }
            Provider.FACEBOOK -> {
                val code = uri.getQueryParameter("code")
                if (code.isNullOrBlank()) {
                    pending = null
                    p.callback(SocialLoginResult.Error(Provider.FACEBOOK, "Missing authorization code"))
                    return
                }
                exchangeFacebookCode(code, p)
            }
        }
    }

    private fun buildGoogleAuthUri(req: OAuthRequest): Uri {
        val scope = req.scopes.joinToString(" ")
        return Uri.parse(SocialLoginConfig.GOOGLE_AUTH_ENDPOINT).buildUpon()
            .appendQueryParameter("client_id", SocialLoginConfig.GOOGLE_CLIENT_ID)
            .appendQueryParameter("redirect_uri", req.redirectUri)
            .appendQueryParameter("response_type", "code")
            .appendQueryParameter("scope", scope)
            .appendQueryParameter("state", req.state)
            .appendQueryParameter("nonce", req.nonce)
            .appendQueryParameter("prompt", "select_account")
            .appendQueryParameter("access_type", "offline")
            .build()
    }

    private fun buildFacebookAuthUri(req: OAuthRequest): Uri {
        val scope = req.scopes.joinToString(",")
        return Uri.parse(SocialLoginConfig.FACEBOOK_AUTH_ENDPOINT).buildUpon()
            .appendQueryParameter("client_id", SocialLoginConfig.FACEBOOK_APP_ID)
            .appendQueryParameter("redirect_uri", req.redirectUri)
            .appendQueryParameter("response_type", "code")
            .appendQueryParameter("scope", scope)
            .appendQueryParameter("state", req.state)
            .build()
    }

    private fun exchangeGoogleCode(code: String, p: Pending) {
        CoroutineScope(Dispatchers.IO).launch {
            try {
                val body: RequestBody = FormBody.Builder()
                    .add("code", code)
                    .add("client_id", SocialLoginConfig.GOOGLE_CLIENT_ID)
                    .add("client_secret", SocialLoginConfig.GOOGLE_CLIENT_SECRET)
                    .add("redirect_uri", p.request.redirectUri)
                    .add("grant_type", "authorization_code")
                    .build()

                val req = Request.Builder()
                    .url(SocialLoginConfig.GOOGLE_TOKEN_ENDPOINT)
                    .post(body)
                    .build()

                val resp = httpClient.newCall(req).execute()
                val text = resp.body?.string().orEmpty()
                if (!resp.isSuccessful) {
                    finishWithError(p, "Google token exchange failed: HTTP ${resp.code} $text")
                    return@launch
                }
                val json = JSONObject(text)
                val accessToken = json.optString("access_token", "")
                val idToken = json.optString("id_token", "")
                val tokenType = json.optString("token_type", null)
                val expiresIn = if (json.has("expires_in")) json.optLong("expires_in") else null

                if (accessToken.isBlank() && idToken.isBlank()) {
                    finishWithError(p, "Google token response missing tokens")
                    return@launch
                }

                finishWithSuccess(
                    p,
                    SocialLoginResult.Success(
                        provider = Provider.GOOGLE,
                        accessToken = accessToken,
                        idToken = idToken.ifBlank { null },
                        tokenType = tokenType,
                        expiresInSeconds = expiresIn,
                        raw = json
                    )
                )
            } catch (t: Throwable) {
                finishWithError(p, "Google token exchange error", t)
            }
        }
    }

    private fun exchangeFacebookCode(code: String, p: Pending) {
        CoroutineScope(Dispatchers.IO).launch {
            try {
                val url = Uri.parse(SocialLoginConfig.FACEBOOK_TOKEN_ENDPOINT).buildUpon()
                    .appendQueryParameter("client_id", SocialLoginConfig.FACEBOOK_APP_ID)
                    .appendQueryParameter("client_secret", SocialLoginConfig.FACEBOOK_APP_SECRET)
                    .appendQueryParameter("redirect_uri", p.request.redirectUri)
                    .appendQueryParameter("code", code)
                    .build()
                    .toString()

                val req = Request.Builder()
                    .url(url)
                    .get()
                    .build()

                val resp = httpClient.newCall(req).execute()
                val text = resp.body?.string().orEmpty()
                if (!resp.isSuccessful) {
                    finishWithError(p, "Facebook token exchange failed: HTTP ${resp.code} $text")
                    return@launch
                }
                val json = JSONObject(text)
                val accessToken = json.optString("access_token", "")
                val tokenType = json.optString("token_type", null)
                val expiresIn = if (json.has("expires_in")) json.optLong("expires_in") else null

                if (accessToken.isBlank()) {
                    finishWithError(p, "Facebook token response missing access_token")
                    return@launch
                }

                finishWithSuccess(
                    p,
                    SocialLoginResult.Success(
                        provider = Provider.FACEBOOK,
                        accessToken = accessToken,
                        idToken = null,
                        tokenType = tokenType,
                        expiresInSeconds = expiresIn,
                        raw = json
                    )
                )
            } catch (t: Throwable) {
                finishWithError(p, "Facebook token exchange error", t)
            }
        }
    }

    private fun finishWithSuccess(p: Pending, result: SocialLoginResult.Success) {
        activity.runOnUiThread {
            if (pending === p) pending = null
            p.callback(result)
        }
    }

    private fun finishWithError(p: Pending, message: String, t: Throwable? = null) {
        if (t != null) Log.e("SocialLoginModule", message, t) else Log.e("SocialLoginModule", message)
        activity.runOnUiThread {
            if (pending === p) pending = null
            p.callback(SocialLoginResult.Error(p.request.provider, message, t))
        }
    }
}

class OAuthBrowserActivity : ComponentActivity() {

    private lateinit var authUri: Uri
    private lateinit var redirectUri: String

    private val launcher: ActivityResultLauncher<Intent> by lazy {
        registerForActivityResult(ActivityResultContracts.StartActivityForResult()) { result ->
            if (result.resultCode != Activity.RESULT_OK) {
                setResult(Activity.RESULT_CANCELED)
                finish()
                return@registerForActivityResult
            }
            val data = result.data
            val redirect = data?.getStringExtra(EXTRA_RESULT_REDIRECT_URI)
            if (redirect.isNullOrBlank()) {
                setResult(Activity.RESULT_CANCELED)
                finish()
                return@registerForActivityResult
            }
            val out = Intent().putExtra(EXTRA_RESULT_REDIRECT_URI, redirect)
            setResult(Activity.RESULT_OK, out)
            finish()
        }
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        val auth = intent.getStringExtra(EXTRA_AUTH_URI)
        val redir = intent.getStringExtra(EXTRA_REDIRECT_URI)
        if (auth.isNullOrBlank() || redir.isNullOrBlank()) {
            setResult(Activity.RESULT_CANCELED)
            finish()
            return
        }
        authUri = Uri.parse(auth)
        redirectUri = redir

        val intent = Intent(this, OAuthRedirectCaptureActivity::class.java).apply {
            putExtra(EXTRA_AUTH_URI, authUri.toString())
            putExtra(EXTRA_REDIRECT_URI, redirectUri)
        }
        launcher.launch(intent)
    }

    companion object {
        const val EXTRA_AUTH_URI = "extra_auth_uri"
        const val EXTRA_REDIRECT_URI = "extra_redirect_uri"
        const val EXTRA_RESULT_REDIRECT_URI = "extra_result_redirect_uri"
    }
}

class OAuthRedirectCaptureActivity : ComponentActivity() {

    private lateinit var authUri: Uri
    private lateinit var redirectUri: String

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        val auth = intent.getStringExtra(OAuthBrowserActivity.EXTRA_AUTH_URI)
        val redir = intent.getStringExtra(OAuthBrowserActivity.EXTRA_REDIRECT_URI)
        if (auth.isNullOrBlank() || redir.isNullOrBlank()) {
            setResult(Activity.RESULT_CANCELED)
            finish()
            return
        }
        authUri = Uri.parse(auth)
        redirectUri = redir

        val viewIntent = Intent(Intent.ACTION_VIEW, authUri).apply {
            addCategory(Intent.CATEGORY_BROWSABLE)
            flags = Intent.FLAG_ACTIVITY_NO_HISTORY or Intent.FLAG_ACTIVITY_NEW_TASK
        }
        startActivity(viewIntent)
    }

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        handleRedirect(intent)
    }

    override fun onResume() {
        super.onResume()
        handleRedirect(intent)
    }

    private fun handleRedirect(intent: Intent?) {
        val data = intent?.data ?: return
        val redir = redirectUri
        val dataStr = data.toString()
        if (!dataStr.startsWith(redir)) return

        val out = Intent().putExtra(OAuthBrowserActivity.EXTRA_RESULT_REDIRECT_URI, dataStr)
        setResult(Activity.RESULT_OK, out)
        finish()
    }
}

class SocialLoginFragment : Fragment() {

    private var module: SocialLoginModule? = null

    override fun onAttach(context: Context) {
        super.onAttach(context)
        val act = requireActivity() as FragmentActivity
        module = SocialLoginModule(act)
    }

    fun loginGoogle(callback: (SocialLoginResult) -> Unit) {
        module?.loginWithGoogle(callback = callback)
    }

    fun loginFacebook(callback: (SocialLoginResult) -> Unit) {
        module?.loginWithFacebook(callback = callback)
    }
}

suspend fun SocialLoginModule.loginGoogleAwait(scopes: List<String> = listOf("openid", "email", "profile")): SocialLoginResult =
    suspendCancellableCoroutine { cont ->
        loginWithGoogle(scopes) { res -> if (cont.isActive) cont.resume(res) }
    }

suspend fun SocialLoginModule.loginFacebookAwait(scopes: List<String> = listOf("public_profile", "email")): SocialLoginResult =
    suspendCancellableCoroutine { cont ->
        loginWithFacebook(scopes) { res -> if (cont.isActive) cont.resume(res) }
    }